  virtual Level databaseAuthLevel(std::string const& username,
                                  std::string const& dbname,
                                  bool configured) = 0;
  virtual Level collectionAuthLevel(std::string const& username,
                                    std::string const& dbname,
                                    std::string_view coll, bool configured) = 0;

